import{_ as a,o as r,c as t,a7 as s}from"./chunks/framework.C5fSpjcB.js";const c=JSON.parse('{"title":"Beginner Guide","description":"","frontmatter":{},"headers":[],"relativePath":"en/guides/beginner.md","filePath":"en/guides/beginner.md","lastUpdated":1775394001000}'),i={name:"en/guides/beginner.md"};function n(o,e,l,d,h,g){return r(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="beginner-guide" tabindex="-1">Beginner Guide <a class="header-anchor" href="#beginner-guide" aria-label="Permalink to &quot;Beginner Guide&quot;">​</a></h1><p>Welcome to Morimens (忘却前夜)! This guide covers everything new players need to know to get started in this roguelite deckbuilding gacha game.</p><h2 id="servers" tabindex="-1">Servers <a class="header-anchor" href="#servers" aria-label="Permalink to &quot;Servers&quot;">​</a></h2><p>Morimens is available on multiple servers:</p><table tabindex="0"><thead><tr><th>Server</th><th>Badge</th><th>Notes</th></tr></thead><tbody><tr><td>China (CN)</td><td><span class="server-badge server-cn">CN</span></td><td>Original server; most content-ahead</td></tr><tr><td>Global</td><td><span class="server-badge server-global">Global</span></td><td>English localization</td></tr><tr><td>Japan (JP)</td><td><span class="server-badge server-jp">JP</span></td><td>Japanese localization; includes rebalancing adjustments</td></tr><tr><td>Taiwan (TW)</td><td><span class="server-badge server-tw">TW</span></td><td>Traditional Chinese localization</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The JP server has received some rebalancing changes that differ from other servers. Check the <a href="./faq.html">FAQ</a> for details on server differences.</p></div><h2 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h2><h3 id="_1-reroll-or-start-playing" tabindex="-1">1. Reroll or Start Playing <a class="header-anchor" href="#_1-reroll-or-start-playing" aria-label="Permalink to &quot;1. Reroll or Start Playing&quot;">​</a></h3><ul><li>The SSR rate is <strong>3%</strong> with a <strong>30-pull pity</strong>. This is generous compared to most gacha games.</li><li>Rerolling is optional but can give you a strong start with an SSR Awakener.</li><li>Do not overlook <span class="rarity-sr">SR</span> characters -- some are excellent and easier to Enlighten.</li></ul><h3 id="_2-progress-the-main-story" tabindex="-1">2. Progress the Main Story <a class="header-anchor" href="#_2-progress-the-main-story" aria-label="Permalink to &quot;2. Progress the Main Story&quot;">​</a></h3><ul><li>Prioritize advancing the <strong>main story</strong> to unlock game features and modes.</li><li>Key unlock: <strong>Stage 3-2</strong> unlocks <a href="./../modes/phase-chess.html">Phase Chess</a> (PvP).</li><li>Story stages reward EXP, currency, and unlock new systems.</li></ul><h3 id="_3-learn-the-card-combat-system" tabindex="-1">3. Learn the Card Combat System <a class="header-anchor" href="#_3-learn-the-card-combat-system" aria-label="Permalink to &quot;3. Learn the Card Combat System&quot;">​</a></h3><p>Morimens is a <strong>turn-based deckbuilding card game</strong>, not a real-time action game:</p><ul><li>You get <strong>5 Arithmetica per turn</strong> to play cards.</li><li>Build <strong>Madness Points</strong> to 100 for a free Madness Burst.</li><li>Accumulate <strong>Silver Key</strong> to 1000 to activate Key Orders.</li><li>Each Awakener has <strong>4 Command Cards + 1 Spirit Awakening Card</strong>.</li></ul><p>See <a href="./../modes/combat.html">Combat System</a> for full details.</p><h3 id="_4-build-your-team" tabindex="-1">4. Build Your Team <a class="header-anchor" href="#_4-build-your-team" aria-label="Permalink to &quot;4. Build Your Team&quot;">​</a></h3><ul><li>Teams consist of up to <strong>4 Awakeners</strong>.</li><li>Match Awakeners by <strong>Designated Realm</strong> for synergy bonuses.</li><li><span class="realm-badge realm-chaos">Chaos</span> Awakeners fit into any team.</li><li>See <a href="./../awakeners/team-building.html">Team Building</a>.</li></ul><h3 id="_5-manage-resources" tabindex="-1">5. Manage Resources <a class="header-anchor" href="#_5-manage-resources" aria-label="Permalink to &quot;5. Manage Resources&quot;">​</a></h3><ul><li><strong>Stamina</strong> -- Spend on resource stages when not progressing story.</li><li><strong>Premium Currency</strong> -- Save for limited banners with Awakeners you want.</li><li><strong>EXP Materials</strong> -- Focus on your core 1-2 DPS characters first.</li><li><strong>Card Upgrade Materials</strong> -- Upgrading cards (up to 6 levels) has a huge impact on combat.</li></ul><h2 id="early-game-priorities" tabindex="-1">Early Game Priorities <a class="header-anchor" href="#early-game-priorities" aria-label="Permalink to &quot;Early Game Priorities&quot;">​</a></h2><ol><li>Clear main story chapters for feature unlocks.</li><li>Level your main DPS Awakener to <strong>25</strong> (unlocks additional skill).</li><li>Upgrade your main DPS&#39;s core Command Cards.</li><li>Build a second Awakener as sub-DPS or Support.</li><li>Start <a href="./../modes/investigation.html">Investigation</a> runs for extra rewards.</li><li>Set up <a href="./../modes/dispatch.html">Dispatch</a> missions for passive income.</li></ol><h2 id="common-beginner-mistakes" tabindex="-1">Common Beginner Mistakes <a class="header-anchor" href="#common-beginner-mistakes" aria-label="Permalink to &quot;Common Beginner Mistakes&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Avoid these common mistakes:</p></div><ul><li><strong>Spreading resources too thin</strong> -- Focus on 1-2 core Awakeners before building others.</li><li><strong>Ignoring card upgrades</strong> -- Card levels matter more than raw stats in many fights.</li><li><strong>Spending premium currency on the standard banner</strong> -- Save for limited banners.</li><li><strong>Skipping daily tasks</strong> -- Consistent daily play is the most efficient way to progress.</li><li><strong>Neglecting realm synergy</strong> -- A realm-matched team of SR Awakeners can outperform a random team of SSRs.</li><li><strong>Adding every card in Investigation</strong> -- Be selective; deck quality matters more than quantity.</li></ul><h2 id="daily-must-dos" tabindex="-1">Daily Must-Dos <a class="header-anchor" href="#daily-must-dos" aria-label="Permalink to &quot;Daily Must-Dos&quot;">​</a></h2><p>See the <a href="./dailies.html">Daily Tasks</a> page for a complete checklist.</p><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./../modes/combat.html">Combat System</a></li><li><a href="./../awakeners/team-building.html">Team Building</a></li><li><a href="./../modes/gacha.html">Gacha / Summoning</a></li><li><a href="./faq.html">FAQ</a></li><li><a href="./dailies.html">Daily Tasks</a></li></ul>',28)])])}const u=a(i,[["render",n]]);export{c as __pageData,u as default};
